10	function stripSensitiveFields(supplier: Record<string, unknown>, isAdmin: boolean) {
11	  if (!isAdmin) {
12	    const { bankingNotes, internalRiskFlag, ...safe } = supplier;
13	    return safe;
14	  }
15	  return supplier;
16	}
