18	@Controller('suppliers')
19	@Roles(Role.PROCUREMENT_MANAGER, Role.ADMINISTRATOR)
20	export class SuppliersController {
21	  constructor(private readonly suppliersService: SuppliersService) {}
22	
23	  @Get()
24	  async findAll(@Query() query: QuerySuppliersDto, @Req() req: Request) {
25	    const result = await this.suppliersService.findAll(query);
26	    const isAdmin = (req.user as { role: string }).role === Role.ADMINISTRATOR;
27	    return {
28	      ...result,
29	      data: result.data.map((s) => stripSensitiveFields(s as unknown as Record<string, unknown>, isAdmin)),
30	    };
31	  }
32	
33	  @Get('dropdown')
34	  async dropdown() {
35	    return this.suppliersService.findAllForDropdown();
36	  }
37	
38	  @Get(':id')
39	  async findOne(@Param('id', ParseUUIDPipe) id: string, @Req() req: Request) {
40	    const supplier = await this.suppliersService.findById(id);
41	    const isAdmin = (req.user as { role: string }).role === Role.ADMINISTRATOR;
42	    return stripSensitiveFields(supplier as unknown as Record<string, unknown>, isAdmin);
43	  }
44	
45	  @Post()
46	  async create(@Body() dto: CreateSupplierDto, @Req() req: Request) {
47	    const supplier = await this.suppliersService.create(dto);
48	    const isAdmin = (req.user as { role: string }).role === Role.ADMINISTRATOR;
49	    return stripSensitiveFields(supplier as unknown as Record<string, unknown>, isAdmin);
50	  }
51	
52	  @Patch(':id')
53	  async update(
54	    @Param('id', ParseUUIDPipe) id: string,
55	    @Body() dto: UpdateSupplierDto,
56	    @Req() req: Request,
57	  ) {
58	    const supplier = await this.suppliersService.update(id, dto);
59	    const isAdmin = (req.user as { role: string }).role === Role.ADMINISTRATOR;
60	    return stripSensitiveFields(supplier as unknown as Record<string, unknown>, isAdmin);
