394	  async getApprovalQueue(query: QueryRequestsDto) {
395	    // Returns all PENDING_APPROVAL requests for the approval queue
396	    const page = parseInt(query.page || '1', 10);
397	    const limit = Math.min(parseInt(query.limit || '20', 10), 100);
398	    const skip = (page - 1) * limit;
399	
400	    const [data, total] = await this.requestRepo.findAndCount({
401	      where: { status: RequestStatus.PENDING_APPROVAL },
402	      relations: ['requester', 'supplier', 'lineItems', 'approvals', 'approvals.approver'],
403	      order: { createdAt: 'ASC' },
404	      skip,
405	      take: limit,
406	    });
407	
408	    return {
409	      data,
410	      meta: { page, limit, total, totalPages: Math.ceil(total / limit) },
411	    };
412	  }
