469	          `${submitted.status === 'APPROVED' ? 'Auto-approved.' : 'Awaiting approval.'}`,
470	        { type: 'PurchaseRequest', id: submitted.id },
471	      );
472	    }
473	
474	    return submitted;
475	  }
