92	  @Get(':supplierId')
93	  @Roles(Role.SUPPLIER)
94	  async getForSupplier(
95	    @Param('supplierId') supplierId: string,
96	    @Req() req: Request,
97	  ) {
98	    const userId = (req.user as { id: string }).id;
99	    const user = await this.usersRepo.findOne({ where: { id: userId } });
100	    if (!user?.supplierId || user.supplierId !== supplierId) {
101	      throw new NotFoundException('Resource not found');
102	    }
103	    return { supplierId };
104	  }
105	}
