3	/**
4	 * Tests for service worker cache isolation and logout invalidation.
5	 *
6	 * We test the SW logic directly by importing and exercising a module-level
7	 * recreation of the cache helpers, mirroring the behaviour in public/sw.js.
8	 */
9	
10	// ── Re-implement the SW cache helpers in a testable module form ───────────────
11	
12	const CACHE_VERSION = 'v2';
13	
14	function makeSwScope() {
15	  let activeUserId: string | null = null;
16	  const storedCaches: Record<string, Map<string, Response>> = {};
17	
18	  const cacheApi = {
19	    open: vi.fn(async (name: string) => {
20	      if (!storedCaches[name]) storedCaches[name] = new Map();
21	      return {
22	        put: vi.fn((req: Request, res: Response) => storedCaches[name].set(req.url, res)),
23	        match: vi.fn(async (req: Request) => storedCaches[name].get(req.url) ?? undefined),
24	      };
25	    }),
26	    keys: vi.fn(async () => Object.keys(storedCaches)),
27	    delete: vi.fn(async (name: string) => { delete storedCaches[name]; return true; }),
28	  };
29	
30	  function userCacheName() {
31	    return activeUserId ? `greenleaf-kb-${CACHE_VERSION}-${activeUserId}` : null;
32	  }
33	
34	  async function networkFirst(request: Request, fetchImpl: typeof fetch) {
35	    const cacheName = userCacheName();
36	    if (!cacheName) return fetchImpl(request);
37	    const cache = await cacheApi.open(cacheName);
38	    try {
39	      const response = await fetchImpl(request);
40	      if ((response as Response).ok) cache.put(request, (response as Response).clone());
41	      return response;
42	    } catch {
43	      const cached = await cache.match(request);
44	      return (
45	        cached ??
46	        new Response(JSON.stringify({ error: 'offline' }), {
47	          status: 503,
48	          headers: { 'Content-Type': 'application/json' },
49	        })
50	      );
51	    }
52	  }
53	
54	  async function clearAllCaches() {
55	    const keys = await cacheApi.keys();
56	    await Promise.all(keys.map((k) => cacheApi.delete(k)));
57	    activeUserId = null;
58	  }
59	
60	  function setUser(userId: string) { activeUserId = userId; }
61	  function getUser() { return activeUserId; }
62	  function getCaches() { return storedCaches; }
63	
64	  return { networkFirst, clearAllCaches, setUser, getUser, getCaches, userCacheName };
65	}
66	
67	// ── Tests ────────────────────────────────────────────────────────────────────
68	
69	describe('Service worker cache isolation', () => {
70	  let sw: ReturnType<typeof makeSwScope>;
71	  let mockFetch: ReturnType<typeof vi.fn>;
72	
73	  const makeReq = (url: string) => new Request(url);
74	  const makeOkRes = (body: string) =>
75	    new Response(body, { status: 200, headers: { 'Content-Type': 'application/json' } });
76	
77	  beforeEach(() => {
78	    sw = makeSwScope();
79	    mockFetch = vi.fn();
80	  });
81	
82	  it('does not cache when no user is set', async () => {
83	    mockFetch.mockResolvedValue(makeOkRes('{"data":[]}'));
84	    const req = makeReq('http://localhost/api/articles?page=1');
85	    await sw.networkFirst(req, mockFetch as unknown as typeof fetch);
86	
87	    // No cache name set → no cache entry
88	    expect(sw.userCacheName()).toBeNull();
89	    expect(Object.keys(sw.getCaches())).toHaveLength(0);
90	  });
91	
92	  it('caches responses under user-scoped key after SET_USER', async () => {
93	    sw.setUser('user-abc');
94	    mockFetch.mockResolvedValue(makeOkRes('{"title":"Plant Care 101"}'));
95	
96	    const req = makeReq('http://localhost/api/articles/1');
97	    await sw.networkFirst(req, mockFetch as unknown as typeof fetch);
98	
99	    const caches = sw.getCaches();
100	    expect(Object.keys(caches)).toContain(`greenleaf-kb-v2-user-abc`);
101	  });
102	
103	  it('separate users get separate cache buckets', async () => {
104	    sw.setUser('user-1');
105	    mockFetch.mockResolvedValue(makeOkRes('{"user":1}'));
106	    await sw.networkFirst(makeReq('http://localhost/api/articles/1'), mockFetch as unknown as typeof fetch);
107	
108	    sw.setUser('user-2');
109	    mockFetch.mockResolvedValue(makeOkRes('{"user":2}'));
110	    await sw.networkFirst(makeReq('http://localhost/api/articles/2'), mockFetch as unknown as typeof fetch);
111	
112	    const caches = sw.getCaches();
113	    expect(Object.keys(caches)).toContain('greenleaf-kb-v2-user-1');
114	    expect(Object.keys(caches)).toContain('greenleaf-kb-v2-user-2');
115	  });
116	
117	  it('clears ALL caches and resets user on CLEAR_CACHE (logout)', async () => {
118	    sw.setUser('user-1');
119	    mockFetch.mockResolvedValue(makeOkRes('{"data":true}'));
120	    await sw.networkFirst(makeReq('http://localhost/api/articles/1'), mockFetch as unknown as typeof fetch);
121	
122	    expect(Object.keys(sw.getCaches())).toHaveLength(1);
123	
124	    await sw.clearAllCaches();
125	
126	    expect(Object.keys(sw.getCaches())).toHaveLength(0);
127	    expect(sw.getUser()).toBeNull();
128	  });
129	
130	  it('serves offline fallback when network fails and no cache exists', async () => {
131	    sw.setUser('user-1');
132	    mockFetch.mockRejectedValue(new Error('Network error'));
133	
134	    const res = await sw.networkFirst(
135	      makeReq('http://localhost/api/articles/99'),
136	      mockFetch as unknown as typeof fetch,
137	    );
138	
139	    expect((res as Response).status).toBe(503);
140	  });
141	
142	  it('serves cached response when offline after prior successful fetch', async () => {
143	    sw.setUser('user-1');
144	
145	    // First: online fetch caches the response
146	    mockFetch.mockResolvedValueOnce(makeOkRes('{"title":"Cached Article"}'));
147	    const req = makeReq('http://localhost/api/articles/5');
148	    await sw.networkFirst(req, mockFetch as unknown as typeof fetch);
149	
150	    // Second: offline, should serve from cache
151	    mockFetch.mockRejectedValueOnce(new Error('offline'));
152	    const res = await sw.networkFirst(req, mockFetch as unknown as typeof fetch);
153	    const body = await (res as Response).text();
154	    expect(body).toContain('Cached Article');
155	  });
156	});
