// ── Re-implement the SW queue helpers in a testable form ──────────────────────

const CACHE_VERSION = 'v2';

interface QueuedOp {
  id: number;
  url: string;
  method: string;
  headers: Record<string, string>;
  body?: string;
  userId: string | null;
  queuedAt: number;
