  function getUser() { return activeUserId; }
  function getQueue() { return [...queue]; }
  function getCaches() { return storedCaches; }

  return {
    networkFirst,
    mutationWithOfflineQueue,
    replayQueue,
    clearAllCaches,
    setUser,
    getUser,
    getQueue,
    getCaches,
    userKbCacheName,
    userOpCacheName,
  };
}

