1	import {
2	  Controller,
3	  Get,
4	  Post,
5	  Param,
6	  Query,
7	  NotFoundException,
8	  ParseUUIDPipe,
9	} from '@nestjs/common';
10	import { Roles } from '../common/decorators/roles.decorator';
11	import { Role } from '../common/enums/role.enum';
12	import { ObservabilityService } from './observability.service';
13	import { SchedulerService } from './scheduler.service';
14	import { QueryLogsDto } from './dto/query-logs.dto';
15	
16	@Controller('admin')
17	@Roles(Role.ADMINISTRATOR)
18	export class ObservabilityController {
19	  constructor(
20	    private readonly observability: ObservabilityService,
21	    private readonly scheduler: SchedulerService,
22	  ) {}
23	
24	  @Get('logs')
25	  async getLogs(@Query() query: QueryLogsDto) {
26	    return this.observability.queryLogs({
27	      level: query.level,
28	      service: query.service,
29	      from: query.from,
30	      to: query.to,
31	      page: query.page ? parseInt(query.page, 10) : undefined,
32	      limit: query.limit ? parseInt(query.limit, 10) : undefined,
33	    });
34	  }
35	
36	  @Get('jobs')
37	  async getJobs() {
38	    return this.observability.getJobMetrics();
39	  }
40	
41	  @Post('jobs/:id/retry')
42	  async retryJob(@Param('id', ParseUUIDPipe) id: string) {
43	    const run = await this.observability.getJobRun(id);
44	    if (!run) throw new NotFoundException('Job run not found');
45	    // Fire and forget — the new run will be tracked in job_runs
46	    void this.scheduler.triggerJob(run.jobName);
47	    return { message: `Job "${run.jobName}" triggered for retry` };
48	  }
49	
50	  @Get('system/stats')
51	  async getSystemStats() {
52	    const [queueStats, systemStats] = await Promise.all([
53	      this.observability.getQueueStats(),
54	      this.observability.getSystemStats(),
55	    ]);
56	    return { queues: queueStats, ...systemStats };
57	  }
58	}
