        return { status: r.status, title: b.data[0]?.title };
      } catch {
        return { status: 0, title: null };
      }
    }, opsUrl);

    await context.setOffline(false);

    expect(result.status).toBe(200);
    expect(result.title).toBe('From Ops Cache');
  });
});
